import reimport jsonimport osimport asynciofrom playwright.async_api import async_playwrightDB_FILE = "leads_sent.json"def calculate_score(url, bio):    score = 50    bio_lower = bio.lower()    if any(t in bio_lower for t in ['ceo', 'founder', 'owner', 'director', 'vp']): score += 30    if '.ai' in url or '.com' in url: score += 20    return min(score, 100)async def scavenge_and_store():    print("Initiating Apex Scrape...")    async with async_playwright() as p:        browser = await p.chromium.launch(headless=True)        page = await browser.new_page()                # Scrape a Google search for high-value targets        await page.goto("https://www.google.com/search?q=site:linkedin.com/in/+\"CEO\"+\"AI Automation\"+\"email\"")        content = await page.content()                # Extract emails using regex        emails = list(set(re.findall(r'[a-zA-Z0-9._%+-]+@[a-zA-Z0-9.-]+\.[a-zA-Z0-9-.]+', content)))                if emails:            target_email = emails[0] # Grab the first valid hit            # Basic placeholder bio/url for the scraped page            target_url = page.url            target_bio = "CEO AI Automation Target"                         lead_score = calculate_score(target_url, target_bio)                        lead_data = {                "email": target_email,                "score": lead_score,                "status": "pending"            }                        # Save to JSON database            db = {"leads": []}            if os.path.exists(DB_FILE):                with open(DB_FILE, 'r') as f:                    try: db = json.load(f)                    except json.JSONDecodeError: pass                        db["leads"].append(lead_data)            db["leads"] = sorted(db["leads"], key=lambda x: x['score'], reverse=True)                        with open(DB_FILE, 'w') as f:                json.dump(db, f, indent=4)                            print(f"Lead acquired: {target_email} | Score: {lead_score}")        else:            print("No new leads found in this cycle.")                    await browser.close()if __name__ == "__main__":    asyncio.run(scavenge_and_store())